import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Box, UserCheck, Search, Filter, Globe } from 'lucide-react';

const PanelCliente = () => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [ofertasFiltradas, setOfertasFiltradas] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  
  // Ubicación dinámica basada en la disponibilidad real de locales
  const [provinciaSel, setProvinciaSel] = useState('Todas');
  const [ciudadSel, setCiudadSel] = useState('Todas');
  const [zonaSel, setZonaSel] = useState('Todas las zonas');

  useEffect(() => {
    // Obtenemos todos los locales para saber dónde hay cobertura
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acumulador = [];

    locales.forEach(local => {
      const ofertasLocal = JSON.parse(localStorage.getItem(`ofertas-local-${local.id}`) || "[]");
      acumulador = [...acumulador, ...ofertasLocal.map(o => ({
        ...o,
        nombreLocal: local.nombre,
        zona: local.zona || 'Centro',
        ciudad: local.ciudad || 'Sin Ciudad',
        provincia: local.provincia || 'Tucumán'
      }))];
    });

    setTodasLasOfertas(acumulador);
  }, []);

  // Lógica de filtrado geográfico multinivel
  useEffect(() => {
    let resultado = todasLasOfertas.filter(o => {
      const coincideBusqueda = o.producto.toLowerCase().includes(busqueda.toLowerCase());
      const coincideProvincia = provinciaSel === 'Todas' || o.provincia === provinciaSel;
      const coincideCiudad = ciudadSel === 'Todas' || o.ciudad === ciudadSel;
      const coincideZona = zonaSel === 'Todas las zonas' || o.zona === zonaSel;
      
      return coincideBusqueda && coincideProvincia && coincideCiudad && coincideZona;
    });
    setOfertasFiltradas(resultado);
  }, [busqueda, provinciaSel, ciudadSel, zonaSel, todasLasOfertas]);

  // Obtenemos valores únicos de los datos reales para los selectores profesionalmente
  const provinciasDisponibles = ['Todas', ...new Set(todasLasOfertas.map(o => o.provincia))];
  const ciudadesDisponibles = ['Todas', ...new Set(todasLasOfertas.filter(o => o.provincia === provinciaSel || provinciaSel === 'Todas').map(o => o.ciudad))];
  const zonasDisponibles = ['Todas las zonas', ...new Set(todasLasOfertas.filter(o => o.ciudad === ciudadSel || ciudadSel === 'Todas').map(o => o.zona))];

  return (
    <div style={{ background: '#f4f7f6', minHeight: '100vh' }}>
      
      {/* BARRA DE NAVEGACIÓN DE UBICACIÓN PROFESIONAL */}
      <div style={navUbicacion}>
        <div style={contenedorUbi}>
          <div style={ubiGroup}>
            <Globe size={18} color="#64748b" />
            <div style={selectBox}>
              <label style={miniLabel}>Provincia</label>
              <select value={provinciaSel} onChange={(e) => {setProvinciaSel(e.target.value); setCiudadSel('Todas');}} style={selectEstilo}>
                {provinciasDisponibles.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
          </div>

          <div style={divisorV} />

          <div style={ubiGroup}>
            <MapPin size={18} color="#64748b" />
            <div style={selectBox}>
              <label style={miniLabel}>Ciudad / Localidad</label>
              <select value={ciudadSel} onChange={(e) => setCiudadSel(e.target.value)} style={selectEstilo}>
                {ciudadesDisponibles.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
          </div>
        </div>

        {/* FILTRO DE ZONAS DINÁMICO CON SCROLL */}
        <div style={zonaWrapper}>
          <div style={zonaScroll}>
            {zonasDisponibles.map(z => (
              <button 
                key={z} 
                onClick={() => setZonaSel(z)}
                style={zonaSel === z ? zonaBtnActive : zonaBtn}
              >
                {z}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div style={{ padding: '30px 5%' }}>
        {/* BUSCADOR DE ALTO IMPACTO */}
        <div style={searchContainer}>
          <Search size={22} color="#94a3b8" />
          <input 
            type="text" 
            placeholder="Buscar por producto, marca o categoría..." 
            style={inputBusqueda}
            onChange={(e) => setBusqueda(e.target.value)}
          />
          <Filter size={22} color="#e67e22" style={{cursor: 'pointer'}} />
        </div>

        <div style={headerResultados}>
          <h2 style={tituloSeccion}>Ofertas en {ciudadSel === 'Todas' ? provinciaSel : ciudadSel}</h2>
          <span style={pillResultados}>{ofertasFiltradas.length} Productos</span>
        </div>
        
        <div style={gridPro}>
          {ofertasFiltradas.length > 0 ? (
            ofertasFiltradas.map(o => (
              <div key={o.id} style={cardPro}>
                <div style={ahorroBadge}>-{Math.round(((o.precioViejo - o.precioNuevo)/o.precioViejo)*100)}% Ahorro</div>
                <div style={imgContainerPro}>
                   {o.imagen ? <img src={o.imagen} alt={o.producto} style={imgFull} /> : <Box size={40} color="#cbd5e1" />}
                </div>
                <div style={cuerpoCard}>
                  <p style={localTag}>{o.nombreLocal} • {o.zona}</p>
                  <h3 style={prodTitle}>{o.producto}</h3>
                  <div style={priceContainer}>
                    <span style={priceMain}>${o.precioNuevo}</span>
                    <span style={priceOff}>${o.precioViejo}</span>
                  </div>
                  <div style={stockRow}>
                    <div style={stockItem}><Box size={14} /> Stock: {o.stock}</div>
                    <div style={stockItem}><UserCheck size={14} /> Límite: {o.limitePorCliente}</div>
                  </div>
                  <button style={btnComprarPro}>
                    <ShoppingCart size={18} /> Reservar Ahora
                  </button>
                </div>
              </div>
            ))
          ) : (
            <div style={emptyStatePro}>
              <Search size={60} color="#cbd5e1" />
              <h3>No hay ofertas en esta ubicación</h3>
              <p>Intenta cambiando la ciudad o provincia para ver más opciones.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

/* --- ESTILOS DE NIVEL EMPRESARIAL --- */
const navUbicacion = { background: 'white', padding: '15px 5%', borderBottom: '1px solid #e2e8f0', sticky: 'top', zIndex: 1000 };
const contenedorUbi = { display: 'flex', alignItems: 'center', background: '#f8fafc', borderRadius: '16px', padding: '10px 20px', marginBottom: '20px', border: '1px solid #f1f5f9' };
const ubiGroup = { display: 'flex', alignItems: 'center', gap: '12px', flex: 1 };
const selectBox = { display: 'flex', flexDirection: 'column', flex: 1 };
const miniLabel = { fontSize: '0.6rem', fontWeight: '800', color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.5px' };
const selectEstilo = { border: 'none', background: 'transparent', fontSize: '0.9rem', fontWeight: '700', color: '#1e293b', outline: 'none', cursor: 'pointer', appearance: 'none' };
